const WHATSAPP_NUMBER = "38976228755";
const RESERVE_MESSAGE = "Hello Rrem's, I would like to reserve a table.";

const menuToggle = document.querySelector(".menu-toggle");
const mobileNav = document.getElementById("mobileNav");
if (menuToggle && mobileNav) {
  menuToggle.addEventListener("click", () => {
    const open = mobileNav.classList.toggle("open");
    menuToggle.setAttribute("aria-expanded", String(open));
  });

  mobileNav.querySelectorAll("a").forEach(link => {
    link.addEventListener("click", () => {
      mobileNav.classList.remove("open");
      menuToggle.setAttribute("aria-expanded", "false");
    });
  });
}

document.querySelectorAll("[data-filter-link]").forEach(link => {
  link.addEventListener("click", () => {
    const filter = link.dataset.filterLink;
    const target = document.getElementById(`cat-${filter}`);
    if (target) setTimeout(() => target.scrollIntoView({ behavior: "smooth", block: "start" }), 80);
  });
});

const modal = document.getElementById("imageModal");
const modalImage = document.getElementById("modalImage");
const modalClose = document.getElementById("modalClose");
let lastFocusedElement = null;

function openModal(button) {
  if (!modal || !modalImage) return;
  lastFocusedElement = document.activeElement;
  modalImage.src = button.dataset.image;
  modalImage.alt = button.dataset.alt;
  modal.classList.add("open");
  modal.setAttribute("aria-hidden", "false");
  modalClose?.focus();
}

function closeModal() {
  if (!modal || !modalImage) return;
  modal.classList.remove("open");
  modal.setAttribute("aria-hidden", "true");
  modalImage.src = "";
  if (lastFocusedElement && typeof lastFocusedElement.focus === "function") lastFocusedElement.focus();
}

document.querySelectorAll(".image-open").forEach(button => {
  button.addEventListener("click", () => openModal(button));
});
if (modalClose) modalClose.addEventListener("click", closeModal);
if (modal) modal.addEventListener("click", event => { if (event.target === modal) closeModal(); });
document.addEventListener("keydown", event => { if (event.key === "Escape") closeModal(); });

const reserveFields = ["guestName", "guestDate", "guestTime", "guestCount", "guestNote"].map(id => document.getElementById(id));
const whatsappButton = document.getElementById("whatsappButton");
const floatingReserve = document.querySelector(".floating-reserve");

function setWhatsAppHref(element, message) {
  if (element) element.href = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(message)}`;
}

function updateWhatsAppLink() {
  const completeFields = reserveFields.every(Boolean);
  if (!completeFields) {
    setWhatsAppHref(whatsappButton, RESERVE_MESSAGE);
    setWhatsAppHref(floatingReserve, RESERVE_MESSAGE);
    return;
  }

  const [name, date, time, guests, note] = reserveFields.map(field => field.value.trim());
  const message = [
    RESERVE_MESSAGE,
    name ? `Name: ${name}` : "Name:",
    date ? `Date: ${date}` : "Date:",
    time ? `Time: ${time}` : "Time:",
    guests ? `Guests: ${guests}` : "Guests:",
    note ? `Note: ${note}` : ""
  ].filter(Boolean).join("\n");

  setWhatsAppHref(whatsappButton, message);
  setWhatsAppHref(floatingReserve, message);
}

reserveFields.forEach(field => { if (field) field.addEventListener("input", updateWhatsAppLink); });
updateWhatsAppLink();
